detailed_optimizations.code_changes:
将kernel_gemm中的循环结构改为：
for (i = 0; i < _PB_NI; i++) {
  for (j = 0; j < _PB_NJ; j++) {
    C[i][j] *= beta;
    for (k = 0; k < _PB_NK; k++) {
      C[i][j] += alpha * A[i][k] * B[k][j];
    }
  }
}

添加分块循环：
int TILE = 32; // 根据L1缓存大小调整
for (ii = 0; ii < _PB_NI; ii += TILE) {
  for (jj = 0; jj < _PB_NJ; jj += TILE) {
    for (kk = 0; kk < _PB_NK; kk += TILE) {
      for (i = ii; i < min(ii+TILE, _PB_NI); i++) {
        for (j = jj; j < min(jj+TILE, _PB_NJ); j++) {
          DATA_TYPE temp = (kk == 0) ? beta * C[i][j] : C[i][j];
          for (k = kk; k < min(kk+TILE, _PB_NK); k++) {
            temp += alpha * A[i][k] * B[k][j];
          }
          C[i][j] = temp;
        }
      }
    }
  }
}

在内层循环添加：
#pragma omp simd
for (k = 0; k < _PB_NK; k += 4) {
  C[i][j] += alpha * A[i][k] * B[k][j];
  C[i][j] += alpha * A[i][k+1] * B[k+1][j];
  C[i][j] += alpha * A[i][k+2] * B[k+2][j];
  C[i][j] += alpha * A[i][k+3] * B[k+3][j];
}
